"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[3137],{6075:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>d,contentTitle:()=>o,default:()=>u,frontMatter:()=>s,metadata:()=>i,toc:()=>l});const i=JSON.parse('{"id":"part2-hands-on/day-2-executive-summary","title":"Day 2 Executive Summary","description":"Day 2 of the RSA Prime enablement, held in person at the Westfield Marriott on July 1, 2026, shifted decisively from Day 1\'s install-and-architecture foundation to the operational craft of running, securing, customizing, and troubleshooting Prime in the field. The day was again delivered in two recorded segments: a 3-hour 3-minute main session (Part 1) and a 17-minute closing module on branding and email templates (Part 2), both led by Ramesh Anand with the in-room team participating hands-on.","source":"@site/Prime Training/part2-hands-on/24-day-2-executive-summary.md","sourceDirName":"part2-hands-on","slug":"/part2-hands-on/day-2-executive-summary","permalink":"/rsapsdocumentation/docs/part2-hands-on/day-2-executive-summary","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":24,"frontMatter":{"title":"Day 2 Executive Summary","sidebar_position":24},"sidebar":"docsSidebar","previous":{"title":"Open Questions and Risk Register","permalink":"/rsapsdocumentation/docs/part1-foundations/open-questions-and-risk-register"},"next":{"title":"Day 2 Session Logistics and Structure","permalink":"/rsapsdocumentation/docs/part2-hands-on/day-2-session-logistics-and-structure"}}');var a=n(4848),r=n(8453);const s={title:"Day 2 Executive Summary",sidebar_position:24},o="Day 2 Executive Summary",d={},l=[];function c(e){const t={em:"em",h1:"h1",header:"header",li:"li",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"day-2-executive-summary",children:"Day 2 Executive Summary"})}),"\n",(0,a.jsx)(t.p,{children:"Day 2 of the RSA Prime enablement, held in person at the Westfield Marriott on July 1, 2026, shifted decisively from Day 1's install-and-architecture foundation to the operational craft of running, securing, customizing, and troubleshooting Prime in the field. The day was again delivered in two recorded segments: a 3-hour 3-minute main session (Part 1) and a 17-minute closing module on branding and email templates (Part 2), both led by Ramesh Anand with the in-room team participating hands-on."}),"\n",(0,a.jsxs)(t.p,{children:["Where Day 1 answered ",(0,a.jsx)(t.em,{children:'"what is Prime and how do I stand it up,"'})," Day 2 answered ",(0,a.jsx)(t.em,{children:'"what will I actually touch during the life of an engagement."'})," The session moved through certificate lifecycle management (including the JKS-to-PEM transition and the Diffie-Hellman parameter requirement), the two runtime configuration files that carry every Quick Setup decision (config.sh and setenv.sh), the completion of the WPI story with the SSP on-demand password-generation feature, a tour of the Prime team's Docker-based development and deployment infrastructure, full build-outs of two suite components previewed on Day 1 \u2014 the Virtual Token Service (VTS) and the Prime Central Authentication Portal (PCAP) \u2014 and finally the branding/CSS customization and email template systems that make Prime look like the customer's own."]}),"\n",(0,a.jsxs)(t.p,{children:["Two qualities distinguished the day. First, it was genuinely hands-on: nearly every topic was demonstrated live, and several demonstrations broke in instructive ways \u2014 the VTS PIN rejection traced through logs to a username mismatch and a software-only mode flag, and an extended PCAP SAML integration debug that traversed certificate paths, keystore generation, and ultimately a WAR-file version patch. The trainer treated each failure as curriculum, repeatedly returning to the day's refrain: ",(0,a.jsx)(t.em,{children:'"logs are your friend."'})," Second, the day surfaced real operational war stories \u2014 most notably a live customer incident from the prior week in which a compromised AMS Bind password (written on paper, exploited internally to create rogue accounts) was remediated on an emergency call using exactly the config.sh procedure taught in the session."]}),"\n",(0,a.jsx)(t.p,{children:"Key outcomes and themes from Day 2 include:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"Certificate replacement is simple but full of traps. Prime now uses PEM-format certificates (three files per application: cert, chain, key); the Diffie-Hellman parameters block in each cert file must be preserved across replacements to avoid reintroducing known vulnerabilities; chains must be ordered lowest-intermediate-first to root; and legacy JKS customers require either JKS-format replacement or conversion."}),"\n",(0,a.jsx)(t.li,{children:"config.sh and setenv.sh are the operational nerve center. Every Quick Setup answer \u2014 ports, certificate references, keystores, encrypted bind credentials, SMTP \u2014 lands in these two per-application files; the bind-password change procedure (Security Console \u2192 encrypt \u2192 paste \u2192 restart) is the canonical field task."}),"\n",(0,a.jsx)(t.li,{children:"Restarts carry latent risk. A one-line change forces a full configuration re-read, so silently expired internal certificates (trust, SAML signing \u2014 which generate no notification) or unnoticed syntax errors surface at the worst moment. Field guidance: restart first to flush latent failures, then make the intended change."}),"\n",(0,a.jsx)(t.li,{children:"The WPI story is now complete end-to-end. The SSP generate-password button (enabled via the allowedUserProfileOperations property) issues a short-lived AD password on demand, with pattern-controlled generation (A/a/N/S syntax), AM acting as the LDAPS proxy, and the Bulk Update scheduler sweeping the temporary password away on its next run."}),"\n",(0,a.jsx)(t.li,{children:"Docker is Prime's future \u2014 driven by Wells Fargo. The trainer's containerized environment (MS/SSP/HTAP containers, one-time setup container, HAProxy, Redis session cache, MailHog) demonstrated near-instant scaling, restart-without-logout, and a build-deploy-restart development loop; Wells Fargo is the first customer deployment."}),"\n",(0,a.jsx)(t.li,{children:"VTS and PCAP moved from concept to buildable. VTS was built end-to-end (builder tool, MTLS certificate trust, secret file, live troubleshoot to success); PCAP was positioned as the sovereign, on-prem CAS equivalent \u2014 the federal/DoD answer where cloud is unavailable \u2014 with SAML/OIDC integration configured in am8config.xml."}),"\n",(0,a.jsx)(t.li,{children:"Branding and email templates are two-file jobs. Look-and-feel lives in common.css and style.css (changes are instant, no restart); every outgoing email is an HTML-plus-properties template pair mapped to operations in the SSP properties."}),"\n"]})]})}function u(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>o});var i=n(6540);const a={},r=i.createContext(a);function s(e){const t=i.useContext(r);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(r.Provider,{value:t},e.children)}}}]);